function cloneGeometryWorldToAncestor(mesh, ancestor) {
  const geometry = mesh.geometry.clone();
  const transform = new THREE.Matrix4()
    .copy(ancestor.matrixWorld)
    .invert()
    .multiply(mesh.matrixWorld);
  geometry.applyMatrix4(transform);
  return geometry;
}

function collectDescendantMeshesLocal(node, ancestor) {
  const geometries = [];
  node.updateMatrixWorld(true);
  ancestor.updateMatrixWorld(true);
  node.traverse((child) => {
    if (child.isMesh && child.geometry) {
      geometries.push({
        name: child.name || 'mesh',
        geometry: cloneGeometryWorldToAncestor(child, ancestor),
      });
    }
  });
  return geometries;
}

function geometryToObj(name, geometry) {
  const nonIndexed = geometry.index ? geometry.toNonIndexed() : geometry.clone();
  const position = nonIndexed.getAttribute('position');
  const lines = ["'`o ${name}`];

  for (let i = 0; i < position.count; i += 1) {
    const x = position.getX(i);
    const y = position.getY(i);
    const z = position.getZ(i);
    lines.push(`v ${x} ${y} ${z}`);
  }

  for (let i = 0; i < position.count; i += 3) {
    lines.push(`f ${i + 1} ${i + 2} ${i + 3}`);
  }

  return `${lines.join('"'\\n')}\\n"'`;
}

function mergeGeometries(geometries) {
  const merged = new THREE.BufferGeometry();
  const vertexArrays = [];
  let totalLength = 0;

  for (const geometry of geometries) {
    const nonIndexed = geometry.index ? geometry.toNonIndexed() : geometry.clone();
    const position = nonIndexed.getAttribute('"'position');
    const array = new Float32Array(position.array);
    vertexArrays.push(array);
    totalLength += array.length;
  }

  const mergedArray = new Float32Array(totalLength);
  let offset = 0;
  for (const array of vertexArrays) {
    mergedArray.set(array, offset);
    offset += array.length;
  }

  merged.setAttribute('position', new THREE.BufferAttribute(mergedArray, 3));
  return merged;
}

function writeObj(filepath, name, geometry) {
  fs.writeFileSync(filepath, geometryToObj(name, geometry), 'utf8');
}

function exportPart(group) {
  const partDir = path.join(PART_MESHES_DIR, group.name);
  fs.mkdirSync(partDir, { recursive: true });

  for (const child of group.children) {
    if (child.isMesh && child.geometry) {
      const geometry = child.geometry.clone();
      geometry.applyMatrix4(child.matrix.clone());
      writeObj(path.join(partDir, "'`${child.name}.obj`), child.name, geometry);
